uniform float uFeed;
uniform float uKill;
out vec4 fragColor;

vec2 sampleAB(vec2 uv) { return texture(sTD2DInputs[0], uv).rg; }

void main()
{
    vec2 uv = vUV.st;
    vec2 texel = uTD2DInfos[0].res.xy;
    vec2 c = sampleAB(uv);
    float a = c.r;
    float b = c.g;

    vec2 lap = vec2(0.0);
    lap += sampleAB(uv + texel * vec2(-1.0, 0.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 1.0, 0.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 0.0,-1.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 0.0, 1.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2(-1.0,-1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2( 1.0,-1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2(-1.0, 1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2( 1.0, 1.0)) * 0.05;
    lap -= c;

    float feed = uFeed > 0.0 ? uFeed : 0.055;
    float kill = uKill > 0.0 ? uKill : 0.062;
    float reaction = a * b * b;
    float da = 1.0 * lap.r - reaction + feed * (1.0 - a);
    float db = 0.5 * lap.g + reaction - (kill + feed) * b;

    float a2 = clamp(a + da, 0.0, 1.0);
    float b2 = clamp(b + db, 0.0, 1.0);
    fragColor = TDOutputSwizzle(vec4(a2, b2, 0.0, 1.0));
}
